with:
  # Helper to decide if a subject name refers to a person (as opposed to an organisation/label)
      def _is_person(name: str) -> bool:
          low = name.lower()
          org_keywords = ["records", "label", "company", "group", "band", "orchestra", "ensemble", ...
          return (" " in name) and not any(k in low for k in org_keywords)

      if len(triples) == 1:
          t = triples[0]
          subj = t.subject
          pred = t.predicate
          obj = t.object.strip().strip('"').strip("'")
          # Simple one‑triple formulations with more natural phrasing.
          if pred == "demonym":
              return f"People from {subj} are called {obj}."
          if pred == "genre":
              # Choose phrasing based on whether the subject is a person or a record label.
              if _is_person(subj):
                  return f"{subj} performs {obj.lower()} music."
              if "records" in subj.lower() or "label" in subj.lower():
                  return f"{subj} is a {obj.lower()} record label."
              return f"{subj} is associated with {obj.lower()} music."
          if pred == "derivative":
              # The object is a derivative of the subject.
              return f"{obj} is a derivative of {subj}."
          if pred == "associatedBand/associatedMusicalArtist":
              # Use a neutral phrasing for musical artist association.
              return f"{subj} is associated with the musician {obj}."
